proof:
have h_card_T : Fintype.card (U k) % 2 = 1 := by
  -- By definition of $U_k$, we know that $|U_k|$ is odd.
  have h_card_U_odd : (Fintype.card (U k)) % 2 = (Fintype.card (fixedPoints (secondInvo k))) % 2 := by
    nontriviality;
    have := @Equiv.Perm.card_fixedPoints_modEq;
    specialize this ( show ( secondInvo k ) ^ 2 ^ 1 = 1 from by simpa using secondInvo_sq k );
    exact this;
  rw [ h_card_U_odd, card_fixedPoints_eq_one ];
rw [ ← sameCard ] ; exact Nat.odd_iff.mpr h_card_T

